mapper.select:
SELECT * FROM (
SELECT m.message_id, m.title, m.content, m.msg_type, m.priority, m.sender_name, m.create_time, r.is_read, r.read_time FROM sys_message m INNER JOIN sys_message_receiver r ON m.message_id = r.message_id WHERE r.receiver_id = #{userId} AND m.del_flag = 0 UNION ALL
SELECT m.message_id, m.title, m.content, m.msg_type, m.priority, m.sender_name, m.create_time, 0 AS is_read, NULL AS read_time FROM sys_message m WHERE m.send_scope = 'ALL' AND m.msg_type != 2 AND m.del_flag = 0 AND NOT EXISTS ( SELECT 1 FROM sys_message_receiver r2 WHERE r2.message_id = m.message_id AND r2.receiver_id = #{userId} ) ) t
AND t.msg_type = #{query.msgType}
AND t.is_read = #{query.isRead}
AND t.title LIKE CONCAT('%', #{query.keyword}, '%')
ORDER BY t.create_time DESC LIMIT #{offset}, #{query.pageSize}

SELECT COUNT(*) FROM (
    SELECT m.message_id, m.msg_type, m.title, r.is_read
    FROM sys_message m
    INNER JOIN sys_message_receiver r ON m.message_id = r.message_id
    WHERE r.receiver_id = #{userId}
      AND m.del_flag = 0
    UNION ALL
    SELECT m.message_id, m.msg_type, m.title, 0 AS is_read
    FROM sys_message m
    WHERE m.send_scope = 'ALL'
      AND m.msg_type != 2
      AND m.del_flag = 0
      AND NOT EXISTS (
          SELECT 1 FROM sys_message_receiver r2
          WHERE r2.message_id = m.message_id AND r2.receiver_id = #{userId}
      )
) t


        AND t.msg_type = #{query.msgType}


        AND t.is_read = #{query.isRead}


        AND t.title LIKE CONCAT('%', #{query.keyword}, '%')

SELECT COUNT(*)
FROM sys_message m
WHERE m.send_scope = 'ALL'
  AND m.msg_type != 2
  AND m.del_flag = 0
  AND NOT EXISTS (
      SELECT 1 FROM sys_message_receiver r2
      WHERE r2.message_id = m.message_id AND r2.receiver_id = #{userId}
  )

  AND m.msg_type = #{msgType}
